-- {"operators": "INNER_JOIN,AGGREGATE,DISTINCT", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": true, "has_case": false, "tables": "ITEM,STOCK,OORDER,ORDER_LINE"}
SELECT i.I_ID, COUNT(DISTINCT CAST((i.I_ID) AS VARCHAR)) AS uniq, COUNT(*) AS cnt FROM ITEM i JOIN STOCK s ON i.I_ID = s.S_I_ID JOIN ORDER_LINE ol ON ol.OL_I_ID = i.I_ID AND ol.OL_SUPPLY_W_ID = s.S_W_ID JOIN OORDER o ON ol.OL_O_ID = o.O_ID AND ol.OL_W_ID = o.O_W_ID GROUP BY i.I_ID;
